INSERT INTO facilities (id, operator_id, name, slug, denomination, description, address, city, state, zip, phone, email, website, plan, subscription_status, is_listed, requires_approval, require_coi, stripe_onboarded, created_at, updated_at) VALUES ('fac-usr-demo-operator', 'usr-demo-operator', 'St. Brigid Community Center', 'st-brigid-community-center', 'Nondenominational', 'A neighborhood community center with spaces for every gathering — from wedding receptions in the Fellowship Hall to workshops, recitals, and shared meals. We believe a building that sits empty is a gift waiting to be given.', '1420 Linden Avenue', 'Minneapolis', 'MN', '55404', '(612) 555-0142', 'hello@stbrigidcenter.org', 'https://stbrigidcenter.org', 'growth', 'active', 1, 0, 1, 1, '2026-06-01T12:00:00.000Z', '2026-06-01T12:00:00.000Z') ON CONFLICT(id) DO NOTHING;
INSERT INTO spaces (id, facility_id, name, space_type, description, capacity_persons, square_footage, hourly_rate_cents, half_day_rate_cents, full_day_rate_cents, weekend_hourly_rate_cents, deposit_amount_cents, amenities, allowed_uses, is_active, created_at, updated_at) VALUES ('spc-hall', 'fac-usr-demo-operator', 'Fellowship Hall', 'fellowship_hall', 'A bright, welcoming hall with hardwood floors, a stage, and a warming kitchen adjacent. Perfect for receptions, fundraisers, and community dinners.', 200, 3200, 12000, 40000, 70000, 15000, 25000, '["stage","kitchen_access","sound_system","wifi","parking","wheelchair_accessible","tables_chairs","restrooms"]', '["wedding","meeting","concert","community","class"]', 1, '2026-06-01T12:00:00.000Z', '2026-06-01T12:00:00.000Z') ON CONFLICT(id) DO NOTHING;
INSERT INTO spaces (id, facility_id, name, space_type, description, capacity_persons, square_footage, hourly_rate_cents, half_day_rate_cents, full_day_rate_cents, weekend_hourly_rate_cents, deposit_amount_cents, amenities, allowed_uses, is_active, created_at, updated_at) VALUES ('spc-chapel', 'fac-usr-demo-operator', 'The Chapel', 'chapel', 'An intimate chapel with warm light and excellent acoustics. A serene setting for small ceremonies, recitals, and gatherings.', 80, 1100, 9000, 30000, 50000, 12000, 20000, '["piano","sound_system","wheelchair_accessible","parking","restrooms"]', '["wedding","concert","community"]', 1, '2026-06-01T12:00:00.000Z', '2026-06-01T12:00:00.000Z') ON CONFLICT(id) DO NOTHING;
INSERT INTO spaces (id, facility_id, name, space_type, description, capacity_persons, square_footage, hourly_rate_cents, half_day_rate_cents, full_day_rate_cents, weekend_hourly_rate_cents, deposit_amount_cents, amenities, allowed_uses, is_active, created_at, updated_at) VALUES ('spc-class', 'fac-usr-demo-operator', 'Classroom 1', 'classroom', 'A flexible classroom with movable tables, a projector, and fast Wi-Fi. Ideal for workshops, tutoring, and small meetings.', 30, 600, 4000, 14000, 24000, 5000, 5000, '["projector","wifi","tables_chairs","air_conditioning","wheelchair_accessible"]', '["class","meeting","community"]', 1, '2026-06-01T12:00:00.000Z', '2026-06-01T12:00:00.000Z') ON CONFLICT(id) DO NOTHING;
